-- Aggregate vote counts per logo
CREATE TABLE IF NOT EXISTS castle_votes (
  logo_id INTEGER PRIMARY KEY,
  up_votes INTEGER NOT NULL DEFAULT 0,
  down_votes INTEGER NOT NULL DEFAULT 0,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Pre-populate all 365 logos with zero votes
INSERT INTO castle_votes (logo_id)
SELECT generate_series(1, 365)
ON CONFLICT (logo_id) DO NOTHING;

-- Per-visitor vote tracking (using anonymous session ID)
CREATE TABLE IF NOT EXISTS castle_user_votes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  logo_id INTEGER NOT NULL REFERENCES castle_votes(logo_id),
  session_id TEXT NOT NULL,
  direction TEXT NOT NULL CHECK (direction IN ('up', 'down')),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(logo_id, session_id)
);

-- Enable RLS
ALTER TABLE castle_votes ENABLE ROW LEVEL SECURITY;
ALTER TABLE castle_user_votes ENABLE ROW LEVEL SECURITY;

-- Allow anyone to read vote counts
CREATE POLICY "public read votes" ON castle_votes FOR SELECT USING (true);

-- Allow anyone to read/write their own session votes
CREATE POLICY "public read user votes" ON castle_user_votes FOR SELECT USING (true);
CREATE POLICY "public insert user votes" ON castle_user_votes FOR INSERT WITH CHECK (true);
CREATE POLICY "public update user votes" ON castle_user_votes FOR UPDATE USING (true);
CREATE POLICY "public delete user votes" ON castle_user_votes FOR DELETE USING (true);

-- Allow anyone to update aggregate counts
CREATE POLICY "public update votes" ON castle_votes FOR UPDATE USING (true);
